eri/","name":"İstanbul Medeniyet Üniversitesi - RoadtoStudy","datePublished":"2025-03-28T13:58:25+03:00","dateModified":"2025-05-02T06:43:11+03:00","isPartOf":{"@id":"https://roadtostudy.com/#website"},"inLanguage":"tr"},{"@type":"Person","@id":"https://roadtostudy.com/author/murat/","name":"Murat","url":"https://roadtostudy.com/author/murat/","image":{"@type":"ImageObject","@id":"https://secure.gravatar.com/avatar/9f5b866231ae7aed7a61015846c1f0ab6c5797b065ec200b93c5e9daa87897af?s=96&amp;d=mm&amp;r=g","url":"https://secure.gravatar.com/avatar/9f5b866231ae7aed7a61015846c1f0ab6c5797b065ec200b93c5e9daa87897af?s=96&amp;d=mm&amp;r=g","caption":"Murat","inLanguage":"tr"}},{"@type":"Article","headline":"İstanbul Medeniyet Üniversitesi - RoadtoStudy","keywords":"Medeniyet Üniversitesi","datePublished":"2025-03-28T13:58:25+03:00","dateModified":"2025-05-02T06:43:11+03:00","author":{"@id":"https://roadtostudy.com/author/murat/","name":"Murat"},"publisher":{"@id":"https://roadtostudy.com/#person"},"description":"İstanbul Medeniyet Üniversitesi: Anadolu Yakası’ndaki devlet üniversitesinde eğitim, kampüs yaşamı ve sosyal imkanları keşfedin!","name":"İstanbul Medeniyet Üniversitesi - RoadtoStudy","@id":"https://roadtostudy.com/istanbul-medeniyet-universitesi-tanitim-rehberi/#richSnippet","isPartOf":{"@id":"https://roadtostudy.com/istanbul-medeniyet-universitesi-tanitim-rehberi/#webpage"},"inLanguage":"tr","mainEntityOfPage":{"@id":"https://roadtostudy.com/istanbul-medeniyet-universitesi-tanitim-rehberi/#webpage"}}]}]}'), '$.content_html', '<div class="wp-block-rank-math-toc-block" id="rank-math-toc"><h2>İçindekiler</h2><nav><ul><li class=""><a href="#universitenin-gecmisi-ve-vizyonu">Üniversitenin Geçmişi ve Vizyonu</a></li><li class=""><a href="#egitim">Eğitim</a></li><li class=""><a href="#kampus-ve-teknolojik-altyapi">Kampüs ve Teknolojik Altyapı</a></li><li class=""><a href="#yurt">Yurt</a></li><li class=""><a href="#sosyal-yasam">Sosyal Yaşam</a></li><li class=""><a href="#u